3	import org.springframework.beans.factory.annotation.Value;
4	import org.springframework.context.annotation.Bean;
5	import org.springframework.context.annotation.Configuration;
6	import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;
7	
8	import java.util.concurrent.Executor;
9	import java.util.concurrent.ThreadPoolExecutor;
10	
11	@Configuration
12	public class IngestionRecoveryAsyncConfig {
13	
14	    @Value("${ingestion.recovery.async.core-size:2}")
15	    private int coreSize;
16	
17	    @Value("${ingestion.recovery.async.max-size:4}")
18	    private int maxSize;
19	
20	    @Value("${ingestion.recovery.async.queue-capacity:100}")
21	    private int queueCapacity;
22	
23	    @Value("${ingestion.recovery.async.keep-alive-seconds:60}")
24	    private int keepAliveSeconds;
25	
26	    @Bean("ingestionRecoveryExecutor")
27	    public Executor ingestionRecoveryExecutor() {
28	        int effectiveCoreSize = Math.max(1, coreSize);
29	        int effectiveMaxSize = Math.max(effectiveCoreSize, maxSize);
30	
31	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
32	        executor.setCorePoolSize(effectiveCoreSize);
33	        executor.setMaxPoolSize(effectiveMaxSize);
34	        executor.setQueueCapacity(queueCapacity);
35	        executor.setKeepAliveSeconds(keepAliveSeconds);
36	        executor.setThreadNamePrefix("ingestion-recovery-");
37	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
38	        executor.initialize();
39	        return executor;
40	    }
41	}
