public class EntityStateResetEvent {
    private final long entityId;
    private final String newFingerprint;

    public EntityStateResetEvent(long entityId, String newFingerprint) {
        this.entityId = entityId;
        this.newFingerprint = newFingerprint;
    }

    public long getEntityId() { return entityId; }
    public String getNewFingerprint() { return newFingerprint; }
}
```

**2. 新建异步通知服务**

```java
// src/main/java/com/fortinet/nac/ingestion/consumer/service/PolicyNotifierService.java
package com.fortinet.nac.ingestion.consumer.service;

import com.fortinet.nac.ingestion.consumer.event.EntityStateResetEvent;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

@Slf4j
@Service
public class PolicyNotifierService {

    private final RestTemplate restTemplate;
    private final String policyServiceUrl;  // 从 @Value 注入

    public PolicyNotifierService(RestTemplate restTemplate,
                                 @Value("${policy.service.reset-url}") String policyServiceUrl) {
        this.restTemplate = restTemplate;
        this.policyServiceUrl = policyServiceUrl;
    }

    @Async("policyReprocessListenerExecutor")  // 复用已有线程池
    @EventListener
    public void onEntityStateReset(EntityStateResetEvent event) {
        try {
            restTemplate.postForObject(policyServiceUrl, event, Void.class);
            log.info("PolicyService notified, entityId={}", event.getEntityId());
        } catch (Exception ex) {
            log.warn("PolicyService notification failed, entityId={}, will not retry",
                     event.getEntityId(), ex);
        }
    }
}
```

**3. Handler 里只加两行**

```java
